// Embeds query via mop-embed (text-embedding-004, 768 dims),
// searches mop_kb Qdrant collection, returns top-K chunks with metadata.
// Input: POST body { query: string, top_k?: number, filters?: { doc_kind?, category?, language? } }

const http   = require('http');
const { execSync } = require('child_process');
function getenv(name) {
  try { return execSync('printenv ' + name, { encoding: 'utf8', shell: '/bin/sh' }).trim(); }
  catch (e) { return ''; }
}
const LITELLM_HOST = 'litellm';
const LITELLM_PORT = 4000;
const QDRANT_HOST  = 'qdrant';
const QDRANT_PORT  = 6333;
const COLLECTION   = 'mop_kb';
const LITELLM_KEY  = getenv('LITELLM_API_KEY') || '';
const QDRANT_KEY   = getenv('QDRANT_API_KEY')  || '';

function httpReq(host, port, method, path, body, extraHeaders) {
  return new Promise((resolve, reject) => {
    const data = body ? JSON.stringify(body) : null;
    const headers = { 'Content-Type': 'application/json', ...(extraHeaders || {}) };
    if (data) headers['Content-Length'] = Buffer.byteLength(data);
    const req = http.request({ hostname: host, port, path, method }, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => {
        const text = Buffer.concat(chunks).toString();
        try { resolve({ status: res.statusCode, data: JSON.parse(text) }); }
        catch (e) { resolve({ status: res.statusCode, data: text }); }
      });
    });
    req.on('error', reject);
    if (data) req.write(data);
    req.end();
  });
}

const input = $input.first().json;
const body  = input.body || input;

const query   = body.query;
const topK    = parseInt(body.top_k, 10) || 5;
const filters = body.filters || {};

if (!query || typeof query !== 'string' || query.trim().length === 0) {
  return [{ json: { ok: false, error: 'missing or empty field: query', statusCode: 400 } }];
}

// 1. Embed query
const embResp = await httpReq(
  LITELLM_HOST, LITELLM_PORT, 'POST', '/v1/embeddings',
  { model: 'mop-embed', input: [query.trim()] },
  { Authorization: `Bearer ${LITELLM_KEY}` }
);
if (embResp.status !== 200) {
  return [{ json: { ok: false, error: 'embed failed: ' + JSON.stringify(embResp.data).slice(0, 200), statusCode: 502 } }];
}
const vector = embResp.data.data[0].embedding;

// 2. Build Qdrant filter
const must = [];
for (const [k, v] of Object.entries(filters)) {
  if (v && typeof v === 'string') {
    must.push({ key: k, match: { value: v } });
  }
}

const searchBody = {
  vector,
  limit: topK,
  with_payload: true,
  score_threshold: 0.4,
};
if (must.length > 0) searchBody.filter = { must };

// 3. Search Qdrant
const searchResp = await httpReq(
  QDRANT_HOST, QDRANT_PORT, 'POST',
  `/collections/${COLLECTION}/points/search`,
  searchBody,
  { 'api-key': QDRANT_KEY }
);
if (searchResp.status !== 200) {
  return [{ json: { ok: false, error: 'qdrant search failed: ' + JSON.stringify(searchResp.data).slice(0, 200), statusCode: 502 } }];
}

// 4. Format results
const hits = (searchResp.data.result || []).map(h => ({
  score:       h.score,
  text:        h.payload.text        || '',
  title:       h.payload.title       || '',
  filename:    h.payload.filename    || '',
  section:     h.payload.section     || '',
  doc_kind:    h.payload.doc_kind    || '',
  category:    h.payload.category    || '',
  language:    h.payload.language    || '',
  namespace:   h.payload.namespace   || '',
  ref_doc_id:  h.payload.ref_doc_id  || '',
  chunk_index: h.payload.chunk_index,
  indexed_at:  h.payload.indexed_at  || '',
}));

return [{ json: { ok: true, query, count: hits.length, hits, statusCode: 200 } }];
